import{_ as l,I as i,c as n,o,a4 as h,J as s}from"./chunks/framework.BR-X7tCu.js";const _=JSON.parse('{"title":"OneBot 适配器配置指南","description":"","frontmatter":{},"headers":[],"relativePath":"docs/guides/adapter_list/onebot_v11_config.md","filePath":"docs/guides/adapter_list/onebot_v11_config.md","lastUpdated":1781968270000}'),r={name:"docs/guides/adapter_list/onebot_v11_config.md"};function d(p,a,c,k,g,b){const e=i("NolebaseGitContributors"),t=i("NolebaseGitChangelog");return o(),n("div",null,[a[0]||(a[0]=h(`<h1 id="onebot-适配器配置指南" tabindex="-1">OneBot 适配器配置指南 <a class="header-anchor" href="#onebot-适配器配置指南" aria-label="Permalink to “OneBot 适配器配置指南”">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to “概述”">​</a></h2><p>OneBot 适配器（<code>onebot_adapter</code>）是 Neo-MoFox 连接 QQ 平台的推荐方式，通过 OneBot 协议与 Napcat QQ 客户端通信。</p><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to “前置条件”">​</a></h2><p>在配置适配器之前，请确保已完成：</p><ol><li>Neo-MoFox 主程序部署（Python 环境 + 依赖安装）</li><li><code>config/core.toml</code> 和 <code>config/model.toml</code> 基础配置</li><li>已安装并登录 <strong>Napcat QQ 客户端</strong></li></ol><h2 id="启用适配器" tabindex="-1">启用适配器 <a class="header-anchor" href="#启用适配器" aria-label="Permalink to “启用适配器”">​</a></h2><p>OneBot 适配器默认已启用。确认 <code>config/plugins/onebot_adapter/config.toml</code> 中：</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">plugin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">enabled = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><h2 id="配置连接参数" tabindex="-1">配置连接参数 <a class="header-anchor" href="#配置连接参数" aria-label="Permalink to “配置连接参数”">​</a></h2><h3 id="配置监听端口" tabindex="-1">配置监听端口 <a class="header-anchor" href="#配置监听端口" aria-label="Permalink to “配置监听端口”">​</a></h3><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">onebot_server</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mode = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;reverse&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # reverse/direct</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">host = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;localhost&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 监听地址</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">port = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8095</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 监听端口</span></span></code></pre></div><h3 id="配置-napcat-客户端" tabindex="-1">配置 Napcat 客户端 <a class="header-anchor" href="#配置-napcat-客户端" aria-label="Permalink to “配置 Napcat 客户端”">​</a></h3><p>在 Napcat QQ 客户端中：</p><ol><li>点击&quot;网络配置&quot; → &quot;WebSocket 客户端&quot; → &quot;新建&quot;</li><li>URL 填写 <code>ws://127.0.0.1:8095</code>（端口与上面的 <code>port</code> 一致）</li><li>保存</li></ol><h2 id="启动" tabindex="-1">启动 <a class="header-anchor" href="#启动" aria-label="Permalink to “启动”">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.py</span></span></code></pre></div><p>日志中出现 <code>[OneBot 适配器] Bot xxxxxxx 连接成功</code> 即表示连接建立。</p><h2 id="故障排除" tabindex="-1">故障排除 <a class="header-anchor" href="#故障排除" aria-label="Permalink to “故障排除”">​</a></h2><ul><li><strong>端口不通</strong>：检查 <code>port</code> 值是否与 Napcat 客户端一致</li><li><strong>连接失败</strong>：确认 Napcat QQ 已登录在线</li><li><strong>不回复消息</strong>：检查 <code>model.toml</code> 的 API Key 是否有效，以及白名单设置</li></ul>`,20)),s(e),s(t)])}const E=l(r,[["render",d]]);export{_ as __pageData,E as default};
